// Obtenemos el resultado de Redis: Buscar usuarios activos
const result = $input.first().json;

// Extraemos las llaves 'ts_' de forma eficiente
const keys = Object.keys(result).filter(k => k.startsWith('ts_'));

// GUARDIA DE RENDIMIENTO: Si Redis está vacío, salimos de inmediato.
// Esto evita que n8n intente procesar nodos vacíos cada 2 segundos.
if (keys.length === 0) return [];

// Mapeamos las llaves a la estructura que necesitan los siguientes nodos
return keys.map(key => {
  const userId = key.slice(3); // Más rápido que .replace('ts_', '')
  return {
    json: {
      tsKey: key,
      userId: userId,
      bufferKey: `buffer_${userId}`,
      metaKey: `meta_${userId}`
    }
  };
});

// Usamos .first() en lugar de .item para evitar el error de iteración
const bufferData = $('Redis: Leer Buffer').first().json;
const metaData   = $('Redis: Leer Meta').first().json;
const userData   = $('Code: Expandir usuarios').first().json;

const rawBuffer   = bufferData.value || '';
const idMensajero = metaData.value  || '947279508470714';

const mensajesUnidos = rawBuffer
  .split('\n')
  .map(m => m.trim())
  .filter(m => m.length > 0)
  .join(' ');

// GUARDIA: Si no hay mensaje real, salimos
if (!mensajesUnidos || mensajesUnidos.length === 0) return [];

return {
  json: {
    from: userData.userId,
    'text.body': mensajesUnidos,
    text: { body: mensajesUnidos },
    'id mensajero': idMensajero,
    'id cliente': `buf_${Date.now()}`,
    profile_name: 'Cliente',
    buffered: true,
    messageCount: rawBuffer.split('\n').filter(m => m.trim()).length
  }
};

