// ── FUENTES DE DATOS ──
const agenteOutput = $('Agente Pedidos').first()?.json?.output ?? '';
const datosUsuario = {
  from:        $('Extractormensajes').first().json.from,
  idMensajero: $('Extractormensajes').first().json['id mensajero'],
  profilename: $('Extractormensajes').first().json.profile_name ?? 'Cliente',
  idMensaje:   $('Extractormensajes').first().json['id cliente'],
};

// ── GUARDIA ──
if (!agenteOutput || agenteOutput.trim().length === 0) {
  return [{ json: { output: 'Lo siento, no pude procesar tu mensaje.', totalfinal: 0, from: datosUsuario.from, 'id mensajero': datosUsuario.idMensajero }}];
}

// ── LIMPIEZA EXTREMA DEL TEXTO (¡Aplica para todo!) ──
let outputLimpio = agenteOutput;

// 1. Limpiar los malditos "[Used tools: ... ]" de LangChain
// Busca el inicio de la herramienta y borra todo hasta el "Result:", deteniéndose justo donde empieza la charla humana.
outputLimpio = outputLimpio.replace(/\[Used tools:[\s\S]*?Result:[\s\S]*?(?:\]\]|\])\s*(?=[A-Z¡¿])/g, '');

// Si por algún motivo extremo el formato cambia y la regex de arriba no lo atrapa, limpieza de emergencia:
if (outputLimpio.includes("[Used tools:")) {
    // Parte el texto desde el último corchete que esté antes de una mayúscula y se queda con lo último
    outputLimpio = outputLimpio.split(/\]\]?\s*(?=[A-Z¡¿])/).pop() || outputLimpio;
}

// 2. Ocultamos el JSON puro que se haya colado en el texto (tu línea original)
outputLimpio = outputLimpio.replace(/\{[\s\S]*?\}/g, '').trim();


// ── DETECCIÓN BASADA EN LA IA (No en Regex) ──
let datosParsed = null;
let metodo = 'FALL';
const matchJSON = agenteOutput.match(/\{[\s\S]*?\}/);

if (matchJSON) {
    try {
        datosParsed = JSON.parse(matchJSON[0]);
        metodo = 'JSON_EXTRAIDO';
    } catch(e) {}
}

// Si la IA generó un JSON válido y con total, es porque entendió que el cliente confirmó
const esConfirmacion = datosParsed !== null && (parseFloat(datosParsed.total) > 0);

if (!esConfirmacion) {
    // Es charla normal, el cliente aún no confirma o está modificando
    return [{ json: {
        output: outputLimpio, // <---- ¡AQUÍ ESTABA EL ERROR ANTES! AHORA USA EL TEXTO LIMPIO
        totalfinal: 0,  // Freno para la DB
        from: datosUsuario.from,
        'id mensajero': datosUsuario.idMensajero,
        id: datosUsuario.idMensaje
    }}];
}

// ── SI ES CONFIRMACIÓN (MODO MÁQUINA) ──
const totalFinal = parseFloat(datosParsed?.total ?? 0) || 0;
const pedidoFinal = datosParsed?.pedido ?? 'Pedido sin detallar';

return [{ json: {
  output:           outputLimpio || '¡Perfecto! Procesando tu orden...',
  nombre:           datosParsed?.nombre || "⚠️ CLIENTE POR IDENTIFICAR",
  direccion:        datosParsed?.direccion ?? 'No especificada',
  metodopago:       datosParsed?.metodopago   ?? 'Efectivo',
  tiposervicio:     datosParsed?.tiposervicio  ?? 'Recojo',
  pedidodetallado:  pedidoFinal,
  total:            totalFinal,
  totalfinal:       totalFinal, // Va a la DB
  telefono:         datosParsed?.telefono  ?? datosUsuario.from,
  metodoextraccion: metodo,
  from:             datosUsuario.from,
  'id mensajero':   datosUsuario.idMensajero,
  id:               datosUsuario.idMensaje,
}}];

// Obtenemos la respuesta exacta del Agente Detector
const respuestaAI = $json.output || "";

// Por defecto, si algo llegara a fallar, asumimos que quiere modificar
let accionFinal = "MODIFICAR"; 

// Buscamos la etiqueta exacta que generó el modelo
if (respuestaAI.includes("ACCIÓN:CONSULTAR")) {
  accionFinal = "CONSULTAR";
} else if (respuestaAI.includes("ACCIÓN:GENERAL")) {
  accionFinal = "GENERAL";
} else if (respuestaAI.includes("ACCIÓN:MODIFICAR")) {
  accionFinal = "MODIFICAR";
} else if (respuestaAI.includes("ACCIÓN:CANCELAR")) {
  accionFinal = "CANCELAR";
}
// Retornamos la acción limpia para que el Switch la lea fácil
return {
  json: {
    output_original: respuestaAI, // Guardamos lo que dijo la IA por si quieres auditar luego
    accion: accionFinal           // Esta es la palabra clave que usará el Switch
  }
};

